export default function Sidebar({ setPage }) {
  return (
    <div
      style={{
        width: "220px",
        height: "100vh",
        background: "#0f172a",
        color: "white",
        padding: "20px"
      }}
    >
      <h2 style={{ marginBottom: "20px" }}>🦷 Dental SaaS</h2>

      <button onClick={() => setPage("dashboard")}>Dashboard</button>
      <br /><br />

      <button onClick={() => setPage("search")}>Search</button>
      <br /><br />

      <button onClick={() => setPage("prescription")}>Prescription</button>
    </div>
  );
}
